import{_ as e,o as t,c as i,S as o}from"./chunks/framework.C6RQlTYc.js";const k=JSON.parse('{"title":"上下文窗口","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_21-context_window.md","filePath":"直击概念/17ai/s_ai_21-context_window.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_21-context_window.md"};function r(n,a,h,s,d,u){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="上下文窗口" tabindex="-1">上下文窗口 <a class="header-anchor" href="#上下文窗口" aria-label="Permalink to &quot;上下文窗口&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>上下文窗口（Context Window）是 LLM <strong>一次能处理的最大 token 数量</strong>，包括输入 prompt 和模型生成的输出。这是 LLM 的&quot;短期记忆&quot;容量上限。</p><ul><li>GPT-4：8K / 32K / 128K tokens</li><li>Claude 3：200K tokens</li><li>Gemini 1.5 Pro：1M tokens</li><li>DeepSeek V3：128K tokens</li></ul><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><h3 id="决定了对话记忆长度" tabindex="-1">决定了对话记忆长度 <a class="header-anchor" href="#决定了对话记忆长度" aria-label="Permalink to &quot;决定了对话记忆长度&quot;">​</a></h3><p>每次 API 调用需要把整个对话历史打包发送。随着对话进行，历史越来越长，最终会超出窗口限制。</p><h3 id="影响信息密度" tabindex="-1">影响信息密度 <a class="header-anchor" href="#影响信息密度" aria-label="Permalink to &quot;影响信息密度&quot;">​</a></h3><p>更大的窗口意味着可以：</p><ul><li>一次上传整本书或长文档进行分析</li><li>进行更复杂的多步推理而不丢失上下文</li><li>同时参考多个文档做出综合判断</li></ul><h3 id="成本与延迟" tabindex="-1">成本与延迟 <a class="header-anchor" href="#成本与延迟" aria-label="Permalink to &quot;成本与延迟&quot;">​</a></h3><p>上下文窗口越大：</p><ul><li>API 调用成本越高（输入 token 按量计费）</li><li>推理延迟越长（需要处理更多 token）</li><li>注意力计算复杂度 O(n²) 增长</li></ul><h2 id="上下文窗口的挑战" tabindex="-1">上下文窗口的挑战 <a class="header-anchor" href="#上下文窗口的挑战" aria-label="Permalink to &quot;上下文窗口的挑战&quot;">​</a></h2><h3 id="lost-in-the-middle" tabindex="-1">Lost in the Middle <a class="header-anchor" href="#lost-in-the-middle" aria-label="Permalink to &quot;Lost in the Middle&quot;">​</a></h3><p>研究表明，LLM 对<strong>开头和结尾</strong>的信息关注最多，对中间部分关注最少。长文档中间的关键信息容易被忽略。</p><h3 id="kv-cache-键值缓存" tabindex="-1">KV Cache（键值缓存） <a class="header-anchor" href="#kv-cache-键值缓存" aria-label="Permalink to &quot;KV Cache（键值缓存）&quot;">​</a></h3><p>Transformer 推理时为每个 token 缓存 K 和 V 矩阵。KV Cache 大小与序列长度成正比：</p><ul><li>8K tokens → 约 256MB</li><li>128K tokens → 约 4GB（单次推理）</li></ul><h3 id="位置编码限制" tabindex="-1">位置编码限制 <a class="header-anchor" href="#位置编码限制" aria-label="Permalink to &quot;位置编码限制&quot;">​</a></h3><p>传统绝对位置编码（如 Sinusoidal）在训练长度之外会出现外推问题。RoPE 等相对位置编码改善了这一问题，但仍有效能衰减。</p><h2 id="位置插值与扩展" tabindex="-1">位置插值与扩展 <a class="header-anchor" href="#位置插值与扩展" aria-label="Permalink to &quot;位置插值与扩展&quot;">​</a></h2><p>为了让预训练时上下文较短的模型（如 4K）支持更长输入（如 32K），常用的方法：</p><ul><li><strong>Position Interpolation</strong>：将新位置的索引线性压缩到训练范围内</li><li><strong>NTK-aware 插值</strong>：高频保留、低频压缩，RoPE 的优化版</li><li><strong>YaRN</strong>：进一步改进，成为长文本扩展的标准方法</li></ul><h2 id="前端实践" tabindex="-1">前端实践 <a class="header-anchor" href="#前端实践" aria-label="Permalink to &quot;前端实践&quot;">​</a></h2><h3 id="上下文管理策略" tabindex="-1">上下文管理策略 <a class="header-anchor" href="#上下文管理策略" aria-label="Permalink to &quot;上下文管理策略&quot;">​</a></h3><ul><li><strong>滑动窗口</strong>：只保留最近 N 轮对话</li><li><strong>摘要压缩</strong>：用模型摘要历史对话替代原文</li><li><strong>智能截断</strong>：优先保留重要信息（最新对话 + 首轮系统 prompt）</li><li><strong>分块处理</strong>：大文档分块处理，每次只提交相关片段</li></ul><h3 id="token-计数" tabindex="-1">Token 计数 <a class="header-anchor" href="#token-计数" aria-label="Permalink to &quot;Token 计数&quot;">​</a></h3><p>使用 tokenizer 工具预估 token 用量：</p><ul><li><code>tiktoken</code>（Python/JS）</li><li>大致的估算：中文 1 字≈1~2 token，英文 1 词≈1.3 token</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>上下文窗口大小如何影响前端架构设计？</li><li>对话进行到第 50 轮时，如何处理超出窗口的历史？</li><li>&quot;Lost in the Middle&quot;现象对前端长文本处理有什么启示？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2307.03172" target="_blank" rel="noreferrer">Lost in the Middle: How Language Models Use Long Contexts</a></li><li><a href="https://arxiv.org/abs/2104.09864" target="_blank" rel="noreferrer">RoPE: Rotary Position Embedding</a></li></ul>',34)])])}const p=e(l,[["render",r]]);export{k as __pageData,p as default};
